        nandaDx: { code: "00000", label: `Riesgo relacionado con ${category}`, rc: "Proceso patológico", mp: "-" },
        noc: "Estado de salud estable.",
        nic: { monitoring: "Signos vitales", management: "Manejo síntomas", education: "Proceso enfermedad" }
