interface PathologiesProps {
    initialQuery?: string;
    initialCategory?: string;
    onNavigate: (view: ViewState) => void;
}

export const Pathologies: React.FC<PathologiesProps> = ({ initialQuery, initialCategory, onNavigate }) => {
    const [query, setQuery] = useState(initialQuery || '');
    const [activeCategory, setActiveCategory] = useState<string | null>(initialCategory || null);
    const [selectedPathology, setSelectedPathology] = useState<Pathology | null>(null);
    const [loading, setLoading] = useState(false);

    // MODO ESTUDIO
    const [studyMode, setStudyMode] = useState(false);
    const [revealedSections, setRevealedSections] = useState<string[]>([]);

    useEffect(() => {
        if (initialQuery) {
            setQuery(initialQuery);
            handleGenerate(initialQuery);
        }
    }, [initialQuery]);

    const handleGenerate = async (term: string) => {
        setLoading(true);
        await new Promise(r => setTimeout(r, 200)); // UX
        let category = "General";
        for (const cat of RAW_CATALOG) {
            if (cat.items.some(i => i.toLowerCase() === term.toLowerCase())) {
                category = cat.category;
                break;
            }
        }
        const offlineData = getOfflinePathology(term, category);
        setSelectedPathology(offlineData);
        setLoading(false);
    };

    const handleItemClick = (item: string) => {
        setQuery(item);
        handleGenerate(item);
    };

    const toggleSection = (section: string) => {
        if (revealedSections.includes(section)) setRevealedSections(prev => prev.filter(s => s !== section));
        else setRevealedSections(prev => [...prev, section]);
    };
    const isBlurred = (section: string) => studyMode && !revealedSections.includes(section);
    const filteredCatalog = RAW_CATALOG.filter(cat => !activeCategory || cat.category === activeCategory);

    // VISTA DE DETALLE (FICHA TÉCNICA)
    if (selectedPathology) {
        return (
            <div className="h-full flex flex-col pb-20 animate-fade-in-right">
                <div className="flex justify-between items-center mb-4 bg-white p-3 rounded-xl border border-slate-200 shadow-sm sticky top-0 z-20">
                    <button onClick={() => setSelectedPathology(null)} className="flex items-center text-slate-600 hover:text-slate-900 font-bold text-xs bg-slate-100 hover:bg-slate-200 px-3 py-2 rounded-lg"><ArrowLeft className="w-4 h-4 mr-2" /> VOLVER</button>
                    <div className="flex gap-2">
                        <div className="flex items-center bg-slate-100 rounded-lg p-1 mr-2">
                            <span className="text-[10px] font-black uppercase text-slate-500 mx-2">Modo Estudio</span>
                            <button onClick={() => setStudyMode(!studyMode)} className={`w-10 h-6 rounded-md flex items-center justify-center ${studyMode ? 'bg-indigo-600 text-white' : 'bg-slate-300 text-slate-500'}`}>{studyMode ? <EyeOff className="w-3 h-3"/> : <Eye className="w-3 h-3"/>}</button>
                        </div>
                        <button className="bg-emerald-600 text-white px-4 py-2 rounded-lg font-bold text-xs flex items-center hover:bg-emerald-700 shadow-md"><Save className="w-4 h-4 mr-2"/> GUARDAR</button>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto bg-white rounded-2xl shadow-xl border border-slate-200">
                     <div className="bg-slate-900 text-white p-6 relative overflow-hidden">
                         <div className="relative z-10">
                            <div className="flex flex-wrap items-center gap-2 mb-3">
                                <span className="bg-emerald-500 text-white text-[10px] font-black px-2 py-1 rounded uppercase">{selectedPathology.system || "General"}</span>
                                {selectedPathology.alert && <span className="bg-red-500 text-white text-[10px] font-black px-2 py-1 rounded uppercase flex items-center animate-pulse"><Siren className="w-3 h-3 mr-1"/> {selectedPathology.alert}</span>}
                            </div>
                            <h1 className="text-3xl font-black tracking-tight mb-2">{selectedPathology.name}</h1>
                            <p className="text-slate-300 font-medium text-sm border-l-4 border-emerald-500 pl-4">{selectedPathology.definition}</p>
                         </div>
                     </div>

                     <div className="p-6 grid lg:grid-cols-3 gap-6">
                         <div className="lg:col-span-2 space-y-6">
                             <section>
                                 <h3 className="flex items-center text-xs font-black text-slate-400 uppercase tracking-widest mb-3 border-b pb-2"><Stethoscope className="w-4 h-4 mr-2 text-indigo-500"/> Clínica</h3>
                                 <div className="grid md:grid-cols-2 gap-4 mb-4">
                                     <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100">
                                         <h4 className="font-bold text-indigo-900 text-xs uppercase mb-2">Etiología</h4>
                                         <p className={`text-sm text-slate-700 ${isBlurred('etiology') ? 'blur-sm select-none' : ''}`} onClick={() => toggleSection('etiology')}>{selectedPathology.etiology}</p>
                                     </div>
                                     <div className="bg-purple-50 p-4 rounded-xl border border-purple-100">
                                         <h4 className="font-bold text-purple-900 text-xs uppercase mb-2">Valoración</h4>
                                         <p className={`text-sm text-slate-700 ${isBlurred('assessment') ? 'blur-sm select-none' : ''}`} onClick={() => toggleSection('assessment')}>{selectedPathology.initialAssessment}</p>
                                     </div>
                                 </div>
                                 <div className="bg-white border border-slate-200 rounded-xl p-5 shadow-sm grid grid-cols-2 gap-6">
                                     <div className={`${isBlurred('symptoms') ? 'blur-md cursor-pointer' : ''}`} onClick={() => toggleSection('symptoms')}>
                                         <h4 className="font-bold text-slate-800 text-xs uppercase mb-2">SÍNTOMAS</h4>
                                         <ul className="space-y-1">{selectedPathology.symptoms?.map((s,i)=><li key={i} className="text-sm text-slate-600 flex items-start"><span className="mr-2 text-indigo-400">•</span>{s}</li>)}</ul>
                                     </div>
                                     <div className={`${isBlurred('signs') ? 'blur-md cursor-pointer' : ''}`} onClick={() => toggleSection('signs')}>
                                         <h4 className="font-bold text-slate-800 text-xs uppercase mb-2">SIGNOS</h4>
                                         <ul className="space-y-1">{selectedPathology.signs?.map((s,i)=><li key={i} className="text-sm text-slate-600 flex items-start"><span className="mr-2 text-emerald-400">•</span>{s}</li>)}</ul>
                                     </div>
                                 </div>
                             </section>

                             <section>
                                 <h3 className="flex items-center text-xs font-black text-slate-400 uppercase tracking-widest mb-3 border-b pb-2 mt-6"><ClipboardList className="w-4 h-4 mr-2 text-emerald-500"/> Cuidados</h3>
                                 <div className={`bg-emerald-50 rounded-xl p-5 border border-emerald-100 mb-4 ${isBlurred('care') ? 'blur-sm' : ''}`} onClick={() => toggleSection('care')}>
                                     <h4 className="font-bold text-emerald-900 text-sm mb-2"><PenTool className="w-4 h-4 inline mr-2"/>Intervenciones</h4>
                                     <ul className="grid md:grid-cols-2 gap-3">{selectedPathology.carePlan?.map((c, i) => <li key={i} className="bg-white p-3 rounded-lg text-sm text-slate-700 border border-emerald-100 shadow-sm flex items-start"><Check className="w-4 h-4 text-emerald-500 mr-2 mt-0.5"/> {c}</li>)}</ul>
                                 </div>
                                 <div className={`bg-white border border-slate-200 rounded-xl p-5 shadow-sm ${isBlurred('pharm') ? 'blur-md' : ''}`} onClick={() => toggleSection('pharm')}>
                                     <h4 className="font-bold text-slate-800 text-xs mb-3 flex items-center uppercase"><Pill className="w-4 h-4 mr-2 text-rose-500"/> Tratamiento</h4>
                                     <div className="flex flex-wrap gap-2">{selectedPathology.treatments?.map((t, i) => <button key={i} onClick={() => onNavigate(ViewState.PHARMACOLOGY)} className="bg-rose-50 text-rose-700 px-3 py-1.5 rounded-lg text-xs font-bold border border-rose-100 hover:bg-rose-100 transition-colors flex items-center"><Pill className="w-3 h-3 mr-1 opacity-50"/> {t}</button>)}</div>
                                 </div>
                             </section>
                         </div>

                         <div className="space-y-6">
                             <div className={`bg-slate-900 text-slate-300 border border-slate-700 rounded-xl p-5 shadow-lg ${isBlurred('nanda') ? 'blur-md' : ''}`} onClick={() => toggleSection('nanda')}>
                                 <h3 className="font-black text-emerald-400 text-xs uppercase mb-4 flex items-center"><Book className="w-4 h-4 mr-2"/> NANDA</h3>
                                 <div className="space-y-4">
                                     <div className="bg-slate-800 p-3 rounded-lg border border-slate-700">
                                         <div className="text-[9px] font-bold text-slate-500 uppercase">Dx Principal</div>
                                         <div className="font-bold text-white text-sm">{selectedPathology.nandaDx?.label}</div>
                                         <div className="text-[10px] text-emerald-500 mt-1 font-mono">CÓDIGO: {selectedPathology.nandaDx?.code}</div>
                                     </div>
                                 </div>
                             </div>

                             <div className={`bg-white border border-slate-200 rounded-xl p-5 shadow-sm space-y-4 ${isBlurred('nocnic') ? 'blur-md' : ''}`} onClick={() => toggleSection('nocnic')}>
                                 <div>
                                     <h4 className="font-black text-slate-800 text-[10px] uppercase mb-2 bg-slate-100 py-1 px-2 rounded w-fit">NOC (Resultados)</h4>
                                     <p className="text-sm text-slate-600 font-medium pl-2 border-l-2 border-slate-300">{selectedPathology.noc}</p>
                                 </div>
