  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isCollapsed, setIsCollapsed] = useState(false);

  const navItems = [
    { label: 'INICIO', view: ViewState.DASHBOARD, icon: Home, hotkey: '1' },
