          `}
      >
          {/* Logo Area */}
          <div className={`p-4 border-b border-slate-800 flex items-center ${isCollapsed ? 'justify-center' : 'justify-between'}`}>
              {!isCollapsed && (
                  <div className="animate-fade-in">
