```tsx
import React, { useState, useEffect } from 'react';
import { Activity, Thermometer, Heart, Wind, ArrowDown, Baby, User, Calculator, Monitor, HeartPulse, AlertTriangle, Brain, RefreshCcw, ChevronDown, ChevronUp, Wand2 } from 'lucide-react';

type AgeGroup = 'ADULT' | 'CHILD' | 'INFANT';

interface VitalRange {
    min: number;
    max: number;
    lowLabel: string;
    highLabel: string;
    actionLow: string;
    actionHigh: string;
}

const RANGES: Record<AgeGroup, Record<string, VitalRange>> = {
    ADULT: {
        FC: { min: 60, max: 100, lowLabel: 'Bradicardia', highLabel: 'Taquicardia', actionLow: 'ECG, valorar atropina', actionHigh: 'Valorar dolor/ansiedad/fiebre' },
        FR: { min: 12, max: 20, lowLabel: 'Bradipnea', highLabel: 'Taquipnea', actionLow: 'Vigilar nivel consciencia', actionHigh: 'Descartar hipoxia/acidosis' },
        TAS: { min: 90, max: 140, lowLabel: 'Hipotensión', highLabel: 'Hipertensión', actionLow: 'Trendelenburg, fluidos', actionHigh: 'Valorar antihipertensivo' },
        TEMP: { min: 36, max: 37.5, lowLabel: 'Hipotermia', highLabel: 'Fiebre', actionLow: 'Manta térmica', actionHigh: 'Antitérmicos, medios físicos' },
        SAT: { min: 95, max: 100, lowLabel: 'Hipoxia', highLabel: '-', actionLow: 'O2 Gafas/Venturi', actionHigh: '-' },
        GLU: { min: 70, max: 140, lowLabel: 'Hipoglucemia', highLabel: 'Hiperglucemia', actionLow: 'Glucosa IV/Oral', actionHigh: 'Insulina según pauta' }
    },
    CHILD: { 
        FC: { min: 70, max: 120, lowLabel: 'Bradicardia', highLabel: 'Taquicardia', actionLow: 'Valorar oxigenación', actionHigh: 'Valorar fiebre' },
        FR: { min: 20, max: 30, lowLabel: 'Bradipnea', highLabel: 'Taquipnea', actionLow: 'Vigilar fatiga', actionHigh: 'Descartar obstrucción' },
        TAS: { min: 80, max: 120, lowLabel: 'Hipotensión', highLabel: 'Hipertensión', actionLow: 'Bolus SF 20ml/kg', actionHigh: 'Calmar al niño' },
        TEMP: { min: 36, max: 37.5, lowLabel: 'Hipotermia', highLabel: 'Fiebre', actionLow: 'Abrigo', actionHigh: 'Antitérmicos' },
        SAT: { min: 95, max: 100, lowLabel: 'Hipoxia', highLabel: '-', actionLow: 'O2, Nebulización', actionHigh: '-' },
        GLU: { min: 60, max: 120, lowLabel: 'Hipoglucemia', highLabel: 'Hiperglucemia', actionLow: 'Gel glucosa', actionHigh: 'Valorar cetoacidosis' }
    },
    INFANT: { 
        FC: { min: 100, max: 160, lowLabel: 'Bradicardia', highLabel: 'Taquicardia', actionLow: 'ESTIMULAR, O2', actionHigh: 'Valorar sepsis' },
        FR: { min: 30, max: 60, lowLabel: 'Bradipnea', highLabel: 'Taquipnea', actionLow: 'Riesgo agotamiento', actionHigh: 'Aleteo/Tiraje?' },
        TAS: { min: 60, max: 90, lowLabel: 'Hipotensión', highLabel: 'Hipertensión', actionLow: 'Expansión volumen', actionHigh: 'Valorar dolor' },
        TEMP: { min: 36.5, max: 37.5, lowLabel: 'Hipotermia', highLabel: 'Fiebre', actionLow: 'Cuna térmica', actionHigh: 'Descartar sepsis' },
        SAT: { min: 94, max: 100, lowLabel: 'Hipoxia', highLabel: '-', actionLow: 'O2, Aspirar', actionHigh: '-' },
        GLU: { min: 45, max: 100, lowLabel: 'Hipoglucemia', highLabel: 'Hiperglucemia', actionLow: 'Glucosa IV 10%', actionHigh: '-' }
    }
};

export const VitalSigns: React.FC = () => {
  const [ageMode, setAgeMode] = useState<AgeGroup>('ADULT');
  const [showGuide, setShowGuide] = useState(false);

  const [fc, setFc] = useState<string>('');
  const [fr, setFr] = useState<string>('');
  const [tas, setTas] = useState<string>('');
  const [tad, setTad] = useState<string>('');
  const [temp, setTemp] = useState<string>('');
  const [sat, setSat] = useState<string>('');
  const [glu, setGlu] = useState<string>('');

  // Advanced Hemodynamics
  const [pam, setPam] = useState<string>('-');
  const [pp, setPp] = useState<string>('-'); // Pulse Pressure
  const [si, setSi] = useState<string>('-'); // Shock Index

  // Calculations
  useEffect(() => {
    if (tas && tad) {
        const s = parseInt(tas);
        const d = parseInt(tad);
        if (s && d) {
            const map = (s + (2 * d)) / 3;
            setPam(map.toFixed(0));
            const pulseP = s - d;
            setPp(pulseP.toFixed(0));
            if (fc) {
                const hr = parseInt(fc);
                const shockIdx = hr / s;
                setSi(shockIdx.toFixed(2));
            } else {
                setSi('-');
            }
        } else {
            setPam('-'); setPp('-'); setSi('-');
        }
    } else {
        setPam('-'); setPp('-'); setSi('-');
    }
  }, [tas, tad, fc]);

  const evaluate = (val: number, type: string) => {
    if (isNaN(val)) return { status: 'neutral', text: '-', action: '' };
    const range = RANGES[ageMode][type] as VitalRange;
    if (!range) return { status: 'neutral', text: '-', action: '' };
    if (val < range.min) return { status: 'low', text: range.lowLabel, action: range.actionLow };
    if (val > range.max) return { status: 'high', text: range.highLabel, action: range.actionHigh };
    return { status: 'normal', text: 'Normal', action: '' };
  };

  const resetVitals = () => {
      setFc(''); setFr(''); setTas(''); setTad(''); setTemp(''); setSat(''); setGlu('');
  };

  const setNormals = () => {
      // Helper to generate a "normal" value within range
      const getNormal = (type: string) => {
          const r = RANGES[ageMode][type];
          return Math.floor((r.min + r.max) / 2).toString();
      };
      setFc(getNormal('FC'));
      setFr(getNormal('FR'));
      setTas(getNormal('TAS'));
      setTad(ageMode === 'ADULT' ? '80' : '60'); // Estimación diastólica
      setTemp('36.5');
      setSat('98');
      setGlu('100');
  };

  const InputRow = ({ label, value, setValue, unit, icon: Icon, type, placeholder = "0" }: any) => {
    const result = value ? evaluate(parseFloat(value), type) : { status: 'neutral', text: '', action: '' };
    let colorClass = "text-slate-500";
    if(result.status === 'high') colorClass = "text-rose-500 font-black animate-pulse";
    if(result.status === 'low') colorClass = "text-blue-500 font-black animate-pulse";
    if(result.status === 'normal') colorClass = "text-emerald-500 font-bold";

    return (
      <div className="flex items-center justify-between bg-slate-800/50 p-3 rounded-xl border border-slate-700 mb-2 transition-all focus-within:ring-2 focus-within:ring-slate-500">
         <div className="flex items-center gap-3">
             <div className={`p-2.5 rounded-lg bg-slate-800 ${colorClass.includes('rose') ? 'bg-rose-900/20' : colorClass.includes('blue') ? 'bg-blue-900/20' : ''} text-slate-300`}>
                 <Icon className="w-6 h-6"/>
             </div>
             <div>
                 <label className="text-[10px] font-bold text-slate-400 uppercase block tracking-wider">{label}</label>
                 {value && <div className={`text-xs uppercase ${colorClass}`}>{result.text || 'Normal'}</div>}
             </div>
         </div>
         <div className="flex items-baseline gap-2">
             <input 
                type="number"
                inputMode="decimal"
                value={value}
                onChange={e => setValue(e.target.value)}
                className="w-24 bg-transparent text-right text-3xl font-mono font-bold text-white outline-none border-b border-slate-600 focus:border-emerald-500 transition-colors placeholder-slate-700"
                placeholder={placeholder}
             />
             <span className="text-xs font-bold text-slate-500 w-8">{unit}</span>
         </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20">
       {/* HEADER */}
       <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col gap-4">
            <div className="flex justify-between items-center">
                <h2 className="font-black text-xl flex items-center text-slate-800">
                    <Monitor className="w-6 h-6 mr-2 text-emerald-600" />
                    MONITOR
                </h2>
                <div className="flex gap-2">
                    <button onClick={setNormals} className="bg-emerald-50 text-emerald-600 font-bold text-[10px] px-3 py-2 rounded-lg hover:bg-emerald-100 flex items-center" aria-label="Cargar Normales">
                        <Wand2 className="w-3 h-3 mr-1"/> NORMAL
                    </button>
                    <button onClick={resetVitals} className="bg-slate-100 text-slate-500 hover:text-red-500 p-2 rounded-lg transition-colors" aria-label="Resetear">
                        <RefreshCcw className="w-5 h-5"/>
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-3 gap-2">
                <button onClick={() => setAgeMode('ADULT')} className={`py-3 rounded-lg text-xs font-bold flex flex-col items-center justify-center transition-all ${ageMode === 'ADULT' ? 'bg-slate-800 text-white shadow ring-2 ring-slate-800' : 'bg-slate-100 text-slate-400'}`}>
                    <User className="w-5 h-5 mb-1"/> ADULTO
                </button>
                <button onClick={() => setAgeMode('CHILD')} className={`py-3 rounded-lg text-xs font-bold flex flex-col items-center justify-center transition-all ${ageMode === 'CHILD' ? 'bg-slate-800 text-white shadow ring-2 ring-slate-800' : 'bg-slate-100 text-slate-400'}`}>
                    <Baby className="w-5 h-5 mb-1"/> NIÑO
                </button>
                <button onClick={() => setAgeMode('INFANT')} className={`py-3 rounded-lg text-xs font-bold flex flex-col items-center justify-center transition-all ${ageMode === 'INFANT' ? 'bg-slate-800 text-white shadow ring-2 ring-slate-800' : 'bg-slate-100 text-slate-400'}`}>
                    <Baby className="w-4 h-4 mb-1"/> BEBÉ
                </button>
            </div>
       </div>

       <div className="grid lg:grid-cols-3 gap-6">
           {/* MONITOR SCREEN */}
           <div className="lg:col-span-2 bg-slate-900 rounded-2xl shadow-2xl p-4 md:p-6 border-4 border-slate-800 relative overflow-hidden">
               {/* Scanlines Effect */}
               <div className="absolute inset-0 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] z-0 pointer-events-none bg-[length:100%_2px,3px_100%]"></div>

               <div className="relative z-10 grid gap-1">
                   <div className="h-12 md:h-16 border-b border-slate-800 mb-2 flex items-center overflow-hidden opacity-50">
                        <svg className="w-full h-full text-emerald-500" viewBox="0 0 300 50">
                            <path fill="none" stroke="currentColor" strokeWidth="2" d="M0,25 L10,25 L15,10 L20,40 L25,25 L35,25 L40,15 L45,25 L300,25" />
                        </svg>
                   </div>

                   <InputRow label="Frecuencia Cardíaca" value={fc} setValue={setFc} unit="lpm" icon={Heart} type="FC" />
                   <InputRow label="Saturación O2" value={sat} setValue={setSat} unit="%" icon={Wind} type="SAT" />

                   <div className="flex gap-2">
                       <div className="flex-1 bg-slate-800/50 p-3 rounded-xl border border-slate-700">
                           <label className="text-[10px] font-bold text-slate-400 uppercase block mb-1">TAS</label>
                           <input type="number" inputMode="decimal" value={tas} onChange={e => setTas(e.target.value)} className="w-full bg-transparent text-right text-3xl font-mono font-bold text-white outline-none border-b border-slate-600 placeholder-slate-700" placeholder="---"/>
                       </div>
                       <div className="flex-1 bg-slate-800/50 p-3 rounded-xl border border-slate-700">
                           <label className="text-[10px] font-bold text-slate-400 uppercase block mb-1">TAD</label>
                           <input type="number" inputMode="decimal" value={tad} onChange={e => setTad(e.target.value)} className="w-full bg-transparent text-right text-3xl font-mono font-bold text-white outline-none border-b border-slate-600 placeholder-slate-700" placeholder="---"/>
                       </div>
                   </div>

                   <div className="grid grid-cols-2 gap-2 mt-2">
                       <InputRow label="Temperatura" value={temp} setValue={setTemp} unit="ºC" icon={Thermometer} type="TEMP" />
                       <InputRow label="Glucemia" value={glu} setValue={setGlu} unit="mg/dL" icon={Calculator} type="GLU" />
                   </div>
               </div>
           </div>

           {/* HEMODYNAMICS PANEL */}
           <div className="space-y-4">
               <div className={`p-5 rounded-xl border-2 transition-all shadow-sm ${pam !== '-' && parseInt(pam) < 65 ? 'bg-rose-50 border-rose-200' : 'bg-white border-slate-200'}`}>
                    <h3 className="text-xs font-black uppercase text-slate-500 mb-2 flex items-center"><Activity className="w-4 h-4 mr-2"/> PRESIÓN MEDIA (PAM)</h3>
                    <div className="flex items-baseline justify-between">
                        <div className={`text-5xl font-black ${pam !== '-' && parseInt(pam) < 65 ? 'text-rose-600' : 'text-slate-800'}`}>{pam}</div>
                        <span className="text-xs font-bold text-slate-400">mmHg</span>
                    </div>
               </div>

               <div className={`p-5 rounded-xl border-2 transition-all shadow-sm ${pp !== '-' && parseInt(pp) < 30 ? 'bg-orange-50 border-orange-200' : 'bg-white border-slate-200'}`}>
                    <h3 className="text-xs font-black uppercase text-slate-500 mb-2 flex items-center"><HeartPulse className="w-4 h-4 mr-2"/> PRESIÓN PULSO (PP)</h3>
                    <div className="flex items-baseline justify-between">
                        <div className={`text-5xl font-black ${pp !== '-' && parseInt(pp) < 30 ? 'text-orange-600' : 'text-slate-800'}`}>{pp}</div>
                        <span className="text-xs font-bold text-slate-400">mmHg</span>
                    </div>
               </div>

               <div className={`p-5 rounded-xl border-2 transition-all shadow-sm ${si !== '-' && parseFloat(si) > 0.9 ? 'bg-rose-100 border-rose-300' : 'bg-white border-slate-200'}`}>
                    <h3 className="text-xs font-black uppercase text-slate-500 mb-2 flex items-center"><AlertTriangle className="w-4 h-4 mr-2"/> ÍNDICE SHOCK (IS)</h3>
                    <div className="flex items-baseline justify-between">
                        <div className={`text-5xl font-black ${si !== '-' && parseFloat(si) > 0.9 ? 'text-rose-700' : 'text-slate-800'}`}>{si}</div>
                        <span className="text-xs font-bold text-slate-400">Ratio</span>
                    </div>
               </div>
           </div>
       </div>

       {/* COLLAPSIBLE REFERENCE GUIDE */}
       <div className="mt-4 bg-white border border-slate-200 rounded-xl overflow-hidden shadow-sm">
           <button onClick={() => setShowGuide(!showGuide)} className="w-full p-4 flex justify-between items-center bg-slate-50 hover:bg-slate-100 transition-colors">
               <div className="flex items-center">
                   <Brain className="w-5 h-5 text-blue-600 mr-2"/>
                   <span className="text-sm font-bold text-slate-700">GUÍA DE REFERENCIA RÁPIDA ({ageMode})</span>
               </div>
               {showGuide ? <ChevronUp className="w-5 h-5 text-slate-400"/> : <ChevronDown className="w-5 h-5 text-slate-400"/>}
           </button>

           {showGuide && (
               <div className="p-4 grid grid-cols-2 md:grid-cols-3 gap-3 bg-white animate-fade-in">
                   {(Object.entries(RANGES[ageMode]) as [string, VitalRange][]).map(([key, range]) => (
                       <div key={key} className="bg-slate-50 p-3 rounded-lg border border-slate-100">
                           <div className="text-[10px] font-black text-slate-400 uppercase mb-1">{key}</div>
                           <div className="text-lg font-black text-slate-800">{range.min} - {range.max}</div>
                           <div className="flex justify-between mt-2 text-[9px] font-bold text-slate-500">
                               <span className="text-blue-500">{range.lowLabel}</span>
                               <span className="text-rose-500">{range.highLabel}</span>
                           </div>
                       </div>
                   ))}
               </div>
           )}
       </div>
    </div>
