            { label: 'Pacientes / HCE', view: ViewState.FOLLOWUP, icon: ClipboardList, hotkey: '2' },
            { label: 'Monitor Constantes', view: ViewState.CONSTANTS, icon: Activity, hotkey: '3' },
        ]
    },
    {
        title: 'RECURSOS Y GUÍAS',
        items: [
            { label: 'Vademécum', view: ViewState.PHARMACOLOGY, icon: Pill, hotkey: '4' },
            { label: 'Biblioteca Patologías', view: ViewState.PATHOLOGIES, icon: BookOpen, hotkey: '5' },
            { label: 'Calculadoras', view: ViewState.CALCULATORS, icon: Calculator, hotkey: '6' },
        ]
    },
    {
        title: 'DOCENCIA',
        items: [
            { label: 'Asistente IA', view: ViewState.ASSISTANT, icon: Bot, hotkey: '7' },
            { label: 'Glosario Médico', view: ViewState.GLOSSARY, icon: GraduationCap, hotkey: '8' },
            { label: 'Buscador Global', view: ViewState.SEARCH, icon: Search, hotkey: 'K' },
        ]
    }
  ];

  // Global Keyboard Shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        // Ctrl+K for Search
        if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
            e.preventDefault();
            onChangeView(ViewState.SEARCH);
            return;
        }
        // Alt+Number for Navigation
        if (e.altKey) {
            const allItems = navGroups.flatMap(g => g.items);
            const item = allItems.find(n => n.hotkey === e.key);
            if (item) {
                e.preventDefault();
                onChangeView(item.view);
            }
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [onChangeView]);

  const handleNavClick = (view: ViewState) => {
    onChangeView(view);
    setIsSidebarOpen(false); // Close mobile menu
  };

  const getPageTitle = () => {
