                            <button key={p.id} onClick={() => setSelectedPatientId(p.id)} className={`w-full text-left p-3 hover:bg-slate-50 transition-all group border-l-4 relative ${isSelected ? 'bg-indigo-50/50 border-indigo-500' : 'bg-white border-transparent hover:border-slate-300'}`}>
