                                    <span className="flex items-center text-orange-400"><Footprints className="w-3 h-3 mr-1"/> CAÍDAS: ALTO</span>
                                    <span className="flex items-center text-amber-400"><BedDouble className="w-3 h-3 mr-1"/> BRADEN: 14</span>
                                </div>
                                <span className="flex items-center text-blue-400"><AlertTriangle className="w-3 h-3 mr-1"/> AISLAMIENTO: ESTÁNDAR</span>
