type TabType = 'EVOLUTION' | 'GRAPHS' | 'BALANCE' | 'PAE' | 'CHECKLIST';
const TAB_ORDER: TabType[] = ['EVOLUTION', 'GRAPHS', 'BALANCE', 'PAE', 'CHECKLIST'];

export const ClinicalFollowUp: React.FC = () => {
    const [patients, setPatients] = useState<Patient[]>(INITIAL_PATIENTS);
    const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<TabType>('EVOLUTION');
    const [isCreatingPatient, setIsCreatingPatient] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const [patientFilter, setPatientFilter] = useState<'ALL'|'CRITICAL'|'MINE'>('ALL');

    // Inputs Evolution
    const [note, setNote] = useState('');
    const [vitals, setVitals] = useState({ ta: '', fc: '', fr: '', sat: '', temp: '', gcs: '' });
    const [activeMacroCat, setActiveMacroCat] = useState('general');

    // Inputs Balance Hídrico
    const [balanceInputs, setBalanceInputs] = useState({ oral: '', parenteral: '', blood: '' });
    const [balanceOutputs, setBalanceOutputs] = useState({ urine: '', stool: '', vomit: '', drain: '' });

    // New Patient Inputs
    const [newName, setNewName] = useState('');
    const [newAge, setNewAge] = useState('');
    const [newDiagnosis, setNewDiagnosis] = useState('');
    const [newBed, setNewBed] = useState('');

    // Touch Handling State
    const touchStartX = useRef(0);
    const touchStartY = useRef(0);
    const touchEndX = useRef(0);
    const touchEndY = useRef(0);

    const filteredPatients = useMemo(() => patients.filter(p => 
        (p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
        p.bed.toLowerCase().includes(searchTerm.toLowerCase())) &&
        (patientFilter === 'ALL' || (patientFilter === 'CRITICAL' && p.history[0]?.riskLevel !== 'STABLE'))
    ), [patients, searchTerm, patientFilter]);

    const selectedPatient = patients.find(p => p.id === selectedPatientId);

    // --- KEYBOARD NAVIGATION & GESTURES ---
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            // FIX: Don't navigate if user is typing in an input
            const target = e.target as HTMLElement;
            if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable) {
                return;
            }

            // Tab Navigation with Ctrl+Arrows
            if ((e.ctrlKey || e.metaKey) && selectedPatientId) {
                if (e.key === 'ArrowRight') {
                    e.preventDefault();
                    const currentIndex = TAB_ORDER.indexOf(activeTab);
                    const nextIndex = Math.min(currentIndex + 1, TAB_ORDER.length - 1);
                    setActiveTab(TAB_ORDER[nextIndex]);
                    return;
                }
                if (e.key === 'ArrowLeft') {
                    e.preventDefault();
                    const currentIndex = TAB_ORDER.indexOf(activeTab);
                    const prevIndex = Math.max(currentIndex - 1, 0);
                    setActiveTab(TAB_ORDER[prevIndex]);
                    return;
                }
            }

            if (!selectedPatientId && filteredPatients.length > 0 && e.key === 'ArrowDown') {
                setSelectedPatientId(filteredPatients[0].id);
                return;
            }

            if (selectedPatientId) {
                const currentIndex = filteredPatients.findIndex(p => p.id === selectedPatientId);

                if (e.key === 'ArrowDown') {
                    e.preventDefault();
                    const nextIndex = Math.min(currentIndex + 1, filteredPatients.length - 1);
                    setSelectedPatientId(filteredPatients[nextIndex].id);
                } else if (e.key === 'ArrowUp') {
                    e.preventDefault();
                    const prevIndex = Math.max(currentIndex - 1, 0);
                    setSelectedPatientId(filteredPatients[prevIndex].id);
                } else if (e.key === 'Escape') {
                    setIsCreatingPatient(false);
                }
            }
        };

        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [selectedPatientId, filteredPatients, activeTab]);

    const handleTouchStart = (e: React.TouchEvent) => {
        touchStartX.current = e.targetTouches[0].clientX;
        touchStartY.current = e.targetTouches[0].clientY;
    };

    const handleTouchMove = (e: React.TouchEvent) => {
        touchEndX.current = e.targetTouches[0].clientX;
        touchEndY.current = e.targetTouches[0].clientY;
    };

    const handleTouchEnd = () => {
        if (!touchStartX.current || !touchEndX.current) return;

        const xDiff = touchStartX.current - touchEndX.current;
        const yDiff = touchStartY.current - touchEndY.current;

        // Check if movement is mostly horizontal (to avoid swipe when scrolling)
        if (Math.abs(xDiff) > Math.abs(yDiff)) {
            const isLeftSwipe = xDiff > 50;
            const isRightSwipe = xDiff < -50;

            if (isLeftSwipe || isRightSwipe) {
                const currentTabIndex = TAB_ORDER.indexOf(activeTab);
                let nextIndex = currentTabIndex;

                if (isLeftSwipe) {
                    nextIndex = Math.min(currentTabIndex + 1, TAB_ORDER.length - 1);
                } else if (isRightSwipe) {
                    nextIndex = Math.max(currentTabIndex - 1, 0);
                }

                if (nextIndex !== currentTabIndex) {
                    setActiveTab(TAB_ORDER[nextIndex]);
                }
            }
        }

        // Reset
        touchStartX.current = 0;
        touchEndX.current = 0;
        touchStartY.current = 0;
        touchEndY.current = 0;
    };

    // --- ACTIONS ---

    const handleCreatePatient = () => {
        if (!newName) return;
        const newP: Patient = {
            id: `p-${Date.now()}`, name: newName, age: newAge, sex: 'M', weight: '70', allergies: 'No conocidas', bed: newBed || 'PEND', diagnosis: newDiagnosis || 'En estudio',
            shiftGoal: '', checklist: { hygiene: false, medication: false, cures: false, diet: false, access: false, position: false },
            activePae: [], history: []
        };
        setPatients([...patients, newP]);
        setSelectedPatientId(newP.id);
        setIsCreatingPatient(false);
        setNewName(''); setNewAge(''); setNewDiagnosis(''); setNewBed('');
    };

    const handleSave = () => {
        if (!selectedPatient || !note) return;

        // Calcular MEWS simple (demo)
        let mews = 0;
        if(vitals.fr && (parseInt(vitals.fr) < 9 || parseInt(vitals.fr) > 20)) mews += 2;
        if(vitals.fc && (parseInt(vitals.fc) < 50 || parseInt(vitals.fc) > 100)) mews += 2;
        if(vitals.sat && parseInt(vitals.sat) < 95) mews += 2;

        const newEvol: Evolution = {
            id: `ev-${Date.now()}`, date: new Date().toISOString(), note, vitals: {...vitals},
            detectedRisks: [], tags: [], riskLevel: mews > 4 ? 'CRITICAL' : mews > 2 ? 'OBSERVATION' : 'STABLE', mewsScore: mews
        };
        const updated = patients.map(p => p.id === selectedPatient.id ? { ...p, history: [newEvol, ...p.history] } : p);
        setPatients(updated);
        setNote('');
        setVitals({ ta: '', fc: '', fr: '', sat: '', temp: '', gcs: '' });
    };

    const addMacro = (text: string) => {
        setNote(prev => prev + text);
    };

    const toggleCheck = (key: keyof typeof selectedPatient.checklist) => {
        if (!selectedPatient) return;
        const updated = patients.map(p => p.id === selectedPatient.id ? { ...p, checklist: { ...p.checklist, [key]: !p.checklist[key] } } : p);
        setPatients(updated);
    };

    const getISBAR = () => {
        if (!selectedPatient) return "";
        return `IDENTIDAD: ${selectedPatient.name}, ${selectedPatient.age}a.\nDX: ${selectedPatient.diagnosis}.\nSITUACIÓN: Estable hemodinámicamente.\nVALORACIÓN: ${note || "Sin cambios recientes."}\nRECOMENDACIÓN: Continuar plan de cuidados.`;
    };

    const calculateBalance = () => {
        const totalIn = (parseFloat(balanceInputs.oral)||0) + (parseFloat(balanceInputs.parenteral)||0) + (parseFloat(balanceInputs.blood)||0);
        const totalOut = (parseFloat(balanceOutputs.urine)||0) + (parseFloat(balanceOutputs.stool)||0) + (parseFloat(balanceOutputs.vomit)||0) + (parseFloat(balanceOutputs.drain)||0);
        return totalIn - totalOut;
    };

    const calculateDiuresisRate = () => {
        const u = parseFloat(balanceOutputs.urine) || 0;
        const w = parseFloat(selectedPatient?.weight || '70');
        // Asumiendo balance de 8 horas para el cálculo rápido
        return (u / w / 8).toFixed(2);
    };

    // Helper for inputs to select all text on focus
    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => e.target.select();

    return (
        <div className="flex flex-col lg:flex-row h-full gap-0 bg-slate-100 pb-20 animate-fade-in text-slate-900">
            {/* --- SIDEBAR: CENSO DE PACIENTES (PROFESSIONAL WARD LIST) --- */}
            <div className={`lg:w-80 bg-white shadow-xl border-r border-slate-200 flex flex-col z-20 shrink-0 ${selectedPatientId ? 'hidden lg:flex' : 'flex w-full'}`}>

                {/* Header Unidad */}
                <div className="p-4 bg-slate-900 text-white shrink-0">
                    <div className="flex justify-between items-center mb-4">
                        <div>
                            <h3 className="font-black text-sm tracking-widest text-emerald-400 uppercase flex items-center"><LayoutList className="w-4 h-4 mr-2"/> UNIDAD 3</h3>
                            <p className="text-[10px] text-slate-400 font-medium">MEDICINA INTERNA B</p>
                        </div>
                        <button onClick={() => setIsCreatingPatient(!isCreatingPatient)} className="bg-emerald-600 hover:bg-emerald-500 text-white p-2 rounded-lg transition-colors shadow-md active:scale-95">
                            {isCreatingPatient ? <X className="w-4 h-4"/> : <UserPlus className="w-4 h-4"/>}
                        </button>
                    </div>

                    {/* Filtros de Carga de Trabajo */}
                    <div className="grid grid-cols-3 gap-1 mb-3 bg-slate-800 p-1 rounded-lg">
                        <button onClick={()=>setPatientFilter('ALL')} className={`text-[9px] font-bold py-1.5 rounded uppercase transition-colors ${patientFilter === 'ALL' ? 'bg-slate-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}>Todos</button>
                        <button onClick={()=>setPatientFilter('CRITICAL')} className={`text-[9px] font-bold py-1.5 rounded uppercase transition-colors ${patientFilter === 'CRITICAL' ? 'bg-rose-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}>Críticos</button>
                        <button onClick={()=>setPatientFilter('MINE')} className={`text-[9px] font-bold py-1.5 rounded uppercase transition-colors ${patientFilter === 'MINE' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-slate-200'}`}>Míos</button>
                    </div>

                    <div className="relative">
                        <Search className="absolute left-2.5 top-2 text-slate-500 w-3.5 h-3.5"/>
                        <input 
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                            placeholder="Buscar paciente o cama..." 
                            className="w-full pl-8 p-1.5 rounded-lg bg-slate-800 border border-slate-700 text-xs text-white placeholder-slate-500 focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                        />
                    </div>
                </div>

                {/* Formulario Nuevo Paciente */}
                {isCreatingPatient && (
                    <div className="p-4 bg-slate-50 border-b border-slate-200 animate-slide-in-top shadow-inner">
                        <h4 className="text-xs font-black text-slate-700 mb-4 uppercase flex items-center bg-slate-200/50 p-2 rounded"><UserPlus className="w-3.5 h-3.5 mr-2 text-indigo-600"/> Nuevo Ingreso</h4>
                        <div className="space-y-3">
                            <div>
                                <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block">Apellidos, Nombre</label>
                                <input value={newName} onChange={e=>setNewName(e.target.value)} className="w-full p-2 text-sm border border-slate-300 rounded bg-white text-slate-900 focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 outline-none font-medium placeholder-slate-300" placeholder="Ej: García Pérez, Juan"/>
                            </div>
                            <div className="flex gap-3">
                                <div className="flex-1">
                                    <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block">Edad</label>
                                    <input value={newAge} onChange={e=>setNewAge(e.target.value)} className="w-full p-2 text-sm border border-slate-300 rounded bg-white text-slate-900 focus:border-indigo-500 outline-none font-medium" placeholder="Años" inputMode="numeric"/>
                                </div>
                                <div className="flex-1">
                                    <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block">Cama</label>
                                    <input value={newBed} onChange={e=>setNewBed(e.target.value)} className="w-full p-2 text-sm border border-slate-300 rounded bg-white text-slate-900 focus:border-indigo-500 outline-none font-medium" placeholder="Ej: 304-A"/>
                                </div>
                            </div>
                            <div>
                                <label className="text-[10px] font-bold text-slate-500 uppercase mb-1 block">Diagnóstico Principal</label>
                                <input value={newDiagnosis} onChange={e=>setNewDiagnosis(e.target.value)} className="w-full p-2 text-sm border border-slate-300 rounded bg-white text-slate-900 focus:border-indigo-500 outline-none font-medium" placeholder="Ej: Neumonía"/>
                            </div>
                            <button onClick={handleCreatePatient} className="w-full bg-indigo-600 text-white py-2.5 rounded-lg text-xs font-bold hover:bg-indigo-700 shadow-md mt-2 transition-colors active:scale-95">CONFIRMAR INGRESO</button>
                        </div>
                    </div>
                )}

                {/* Lista de Pacientes (Censo) */}
                <div className="flex-1 overflow-y-auto divide-y divide-slate-100 bg-white">
                    {filteredPatients.map(p => {
                        const lastLevel = p.history[0]?.riskLevel || 'STABLE';
                        const lastVitals = p.history[0]?.vitals;
                        const isSelected = selectedPatientId === p.id;

                        return (
                            <button key={p.id} onClick={() => setSelectedPatientId(p.id)} className={`w-full text-left p-3 hover:bg-slate-50 transition-all group border-l-4 relative focus:outline-none focus:bg-slate-50 ${isSelected ? 'bg-indigo-50/50 border-indigo-500' : 'bg-white border-transparent hover:border-slate-300'}`}>
                                <div className="flex justify-between items-start mb-2">
                                    <div className="flex gap-3 items-center">
                                        <div className={`w-10 h-10 rounded-lg flex flex-col items-center justify-center font-black text-sm shadow-sm border ${isSelected ? 'bg-indigo-100 text-indigo-700 border-indigo-200' : 'bg-slate-50 text-slate-600 border-slate-200'}`}>
                                            <span className="text-[10px] leading-none opacity-70">CAMA</span>
                                            {p.bed.split('-')[0]}
                                        </div>
                                        <div>
                                            <div className={`font-bold text-sm leading-none mb-1.5 ${isSelected ? 'text-indigo-900' : 'text-slate-800'}`}>{p.name}</div>
                                            <div className="text-[10px] text-slate-500 font-medium flex items-center gap-1.5">
                                                <span className="bg-slate-100 px-1.5 py-0.5 rounded border border-slate-200 text-slate-600">{p.age}A</span>
                                                <span className="truncate max-w-[110px]">{p.diagnosis}</span>
                                            </div>
                                        </div>
                                    </div>
                                    {lastLevel === 'CRITICAL' && <AlertOctagon className="w-4 h-4 text-rose-500 animate-pulse shrink-0"/>}
                                    {lastLevel === 'OBSERVATION' && <AlertTriangle className="w-4 h-4 text-amber-500 shrink-0"/>}
                                </div>
                                {/* Mini Vitals Summary */}
                                <div className="flex gap-2 pl-[52px]">
                                    {lastVitals?.ta && <span className="text-[10px] font-mono text-slate-500 bg-slate-50 px-1.5 rounded border border-slate-100">TA: {lastVitals.ta}</span>}
                                    {lastVitals?.sat && <span className={`text-[10px] font-mono px-1.5 rounded border ${parseInt(lastVitals.sat) < 92 ? 'text-rose-600 bg-rose-50 border-rose-100' : 'text-slate-500 bg-slate-50 border-slate-100'}`}>Sat: {lastVitals.sat}%</span>}
                                </div>
                            </button>
                        );
                    })}
                </div>
            </div>

            {/* --- MAIN WORKSPACE: HCE (HISTORIA CLÍNICA) --- */}
            <div 
                className={`flex-1 flex flex-col bg-white overflow-hidden h-full relative ${!selectedPatientId ? 'hidden lg:flex' : 'flex'}`}
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
            >
                {selectedPatient ? (
                    <>
                        {/* 1. PATIENT BANNER (SEGURIDAD Y DEMOGRÁFICOS) */}
                        <div className="bg-slate-900 text-white shrink-0 shadow-md relative overflow-hidden z-10">

                            {/* Barra de Alertas Críticas */}
                            <div className="bg-slate-950 px-4 py-1.5 flex justify-between items-center text-[10px] font-bold uppercase tracking-widest border-b border-slate-800">
                                <div className="flex gap-4">
                                    <span className={`flex items-center ${selectedPatient.allergies !== 'No conocidas' ? 'text-rose-500 animate-pulse' : 'text-slate-500'}`}>
                                        <ShieldAlert className="w-3 h-3 mr-1"/> ALERGIAS: {selectedPatient.allergies}
                                    </span>
                                    <span className="hidden md:flex items-center text-purple-400"><Heart className="w-3 h-3 mr-1"/> RCP: COMPLETA</span>
                                    <span className="hidden md:flex items-center text-orange-400"><Footprints className="w-3 h-3 mr-1"/> CAÍDAS: ALTO</span>
                                </div>
                                <span className="flex items-center text-blue-400"><AlertTriangle className="w-3 h-3 mr-1"/> AISLAMIENTO: ESTÁNDAR</span>
                            </div>

                            {/* Cabecera Principal */}
                            <div className="p-4 flex flex-col md:flex-row gap-4 items-start md:items-center justify-between relative z-10">
                                <div className="flex items-center gap-4 w-full md:w-auto">
                                    <button onClick={() => setSelectedPatientId(null)} className="lg:hidden p-2 bg-slate-800 rounded-full hover:bg-slate-700 text-slate-300 active:scale-95 transition-transform"><ArrowLeft className="w-4 h-4"/></button>
                                    <div className="w-12 h-12 bg-indigo-600 rounded-xl flex items-center justify-center text-xl font-black shadow-lg border-2 border-slate-800 shrink-0">
                                        {selectedPatient.name.charAt(0)}
                                    </div>
