const generateOfflinePathology = (name: string, categoryName: string): Pathology => {
  const template = CATEGORY_TEMPLATES['default'];
  return {
    id: `auto-${name.replace(/\s+/g, '-').toLowerCase()}`,
    name: name,
    definition: `Patología clasificada en ${categoryName}. Se caracteriza por alteraciones fisiológicas que requieren cuidados de enfermería especializados.`,
    system: categoryName,
    etiology: template.etiology || "No especificada",
    initialAssessment: template.initialAssessment || "Valoración general",
    patterns: template.patterns || "Variable",
    clinicalNote: template.clinicalNote || "Consultar protocolos del centro.",
    treatments: template.treatments || [],
    carePlan: template.carePlan || [],
    complications: template.complications || [],
    dischargePlanning: template.dischargePlanning || [],
    tags: template.tags as any,
    symptoms: template.symptoms as string[],
    signs: template.signs as string[],
    alert: template.alert as string,
    nandaDx: template.nandaDx as any,
    noc: template.noc as string,
    nic: template.nic as any
  };
};

const INITIAL_FORM_STATE: Pathology = {
    id: '', name: '', definition: '', system: '', etiology: '', initialAssessment: '', patterns: '', clinicalNote: '',
    treatments: [], carePlan: [], complications: [], dischargePlanning: [], tags: { nanda: '', pharm: '', class: '' },
    symptoms: [], signs: [], alert: '', nandaDx: { code: '', label: '', rc: '', mp: '' }, noc: '',
    nic: { monitoring: '', management: '', education: '' }
};

interface PathologiesProps {
    initialQuery?: string;
    initialCategory?: string;
    onNavigate: (view: ViewState, params?: any) => void;
}

export const Pathologies: React.FC<PathologiesProps> = ({ initialQuery, initialCategory, onNavigate }) => {
  const [query, setQuery] = useState(initialQuery || '');
  const [selectedCategory, setSelectedCategory] = useState<string>(initialCategory || 'Cardiología');
  const [loading, setLoading] = useState(false);
  const [data, setData] = useState<Pathology | null>(null);
  const [viewMode, setViewMode] = useState<'SEARCH' | 'CREATE'>('SEARCH');
  const [customPathologies, setCustomPathologies] = useState<Pathology[]>([]);
  const [isSaved, setIsSaved] = useState(false);
  const [isStudyMode, setIsStudyMode] = useState(false);
  const [personalNotes, setPersonalNotes] = useState('');

  // Create Form State
  const [formData, setFormData] = useState<Pathology>(INITIAL_FORM_STATE);
  const [isAutoFilling, setIsAutoFilling] = useState(false);
  const [createTab, setCreateTab] = useState<'GENERAL' | 'CLINICAL' | 'PAE' | 'TX'>('GENERAL');

  // Effect to handle initial search
  useEffect(() => {
    if (initialQuery) {
        setQuery(initialQuery);
        executeSearch(initialQuery);
    }
    if (initialCategory) setSelectedCategory(initialCategory);
  }, [initialQuery, initialCategory]);

  useEffect(() => {
    if (!data) { setIsSaved(false); setPersonalNotes(''); return; }
    const exists = Object.values(STATIC_DB).some(p => p.name === data.name) || customPathologies.some(p => p.name === data.name);
    setIsSaved(exists);
  }, [data, customPathologies]);

  const organizedCatalog = useMemo(() => {
    let catalog = RAW_CATALOG.map(cat => ({ ...cat, items: [...cat.items] }));
    const unclassified: string[] = [];
    customPathologies.forEach(p => {
        const cat = catalog.find(c => c.category === p.system);
        if (cat && !cat.items.includes(p.name)) cat.items.push(p.name);
        else if (!cat) unclassified.push(p.name);
    });
    if (unclassified.length > 0) catalog.push({ category: 'Personal', icon: Database, color: 'text-gray-600', bg: 'bg-gray-100', border: 'border-gray-300', items: unclassified });

    return catalog.map(cat => ({
        ...cat,
        items: cat.items.sort()
    }));
  }, [customPathologies]);

  const executeSearch = async (term: string) => {
    setViewMode('SEARCH');
    setData(null);
    const normalized = term.toLowerCase();

    // 1. Search in STATIC_DB
    const staticKey = Object.keys(STATIC_DB).find(k => k.toLowerCase() === normalized);
    if (staticKey) { setData(STATIC_DB[staticKey]); return; }

    // 2. Search in Custom
    const custom = customPathologies.find(p => p.name.toLowerCase() === normalized);
    if (custom) { setData(custom); return; }

    // 3. Search in Catalog (Offline Gen)
    let catName = '';
    for (const c of RAW_CATALOG) {
        if (c.items.some(i => i.toLowerCase() === normalized)) { catName = c.category; break; }
    }
    if (catName) {
        setData(generateOfflinePathology(term, catName));
        return;
    }

    // 4. AI Fallback
    setLoading(true);
    try {
        const result = await generatePathology(term);
        setData(result);
    } catch (e) {
        alert("Error generando patología.");
    } finally {
        setLoading(false);
    }
  };

  const handleSave = () => {
    if (data && !isSaved) {
        setCustomPathologies(prev => [...prev, data]);
        setIsSaved(true);
    }
  };

  const handleAutoFill = async () => {
     if(!formData.name) return;
     setIsAutoFilling(true);
     try {
         const res = await generatePathology(formData.name);
         setFormData(res);
     } catch(e) { alert("Error IA"); } finally { setIsAutoFilling(false); }
  };

  const handleManualCreate = () => {
      setCustomPathologies(prev => [...prev, { ...formData, id: `manual-${Date.now()}` }]);
      setViewMode('SEARCH');
      setFormData(INITIAL_FORM_STATE);
  };

  const currentCategoryData = organizedCatalog.find(c => c.category === selectedCategory);
  const blurClass = isStudyMode ? "blur-sm select-none hover:blur-none transition-all duration-300 cursor-help" : "";

  return (
    <div className="flex h-full gap-0 bg-slate-100 overflow-hidden">

       {/* --- SIDEBAR: CATEGORIES --- */}
       <div className={`w-72 bg-white border-r border-slate-200 flex flex-col shrink-0 z-10 ${data ? 'hidden lg:flex' : 'flex'}`}>
           <div className="p-4 bg-slate-900 text-white shadow-sm">
               <h2 className="text-xs font-black tracking-widest uppercase flex items-center mb-1"><BookOpen className="w-4 h-4 mr-2"/> BIBLIOTECA CLÍNICA</h2>
               <p className="text-[10px] text-slate-400">Base de datos de patologías</p>
           </div>

           <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-1">
               {organizedCatalog.map(cat => (
                    <button 
                        key={cat.category} 
                        onClick={() => { setSelectedCategory(cat.category); setData(null); }}
                        className={`w-full flex items-center justify-between p-3 rounded-lg text-sm font-bold transition-all group ${selectedCategory === cat.category ? `${cat.bg} ${cat.color} ring-1 ring-inset ring-current` : 'bg-white text-slate-600 hover:bg-slate-50 border border-transparent'}`}
                    >
                        <div className="flex items-center">
                            <cat.icon className={`w-4 h-4 mr-3 ${selectedCategory === cat.category ? '' : 'text-slate-400 group-hover:text-slate-600'}`} /> 
                            {cat.category}
                        </div>
                        <span className={`text-[10px] px-2 py-0.5 rounded-full font-black ${selectedCategory === cat.category ? 'bg-white/50' : 'bg-slate-100 text-slate-400'}`}>{cat.items.length}</span>
                    </button>
                ))}
           </div>
       </div>

       {/* --- MAIN CONTENT --- */}
       <div className="flex-1 flex flex-col relative bg-slate-50 overflow-hidden">

           {/* TOP SEARCH BAR */}
           <div className="bg-white p-3 border-b border-slate-200 shadow-sm flex items-center gap-3 z-20 shrink-0">
               <button onClick={() => { setSelectedCategory(organizedCatalog[0].category); setData(null); }} className="lg:hidden p-2 text-slate-500 bg-slate-100 rounded-lg"><Layout className="w-5 h-5"/></button>
               <div className="flex-1 relative">
                   <Search className="absolute left-3 top-2.5 w-4 h-4 text-slate-400" />
                   <input 
                     type="text" 
                     className="w-full pl-9 pr-4 py-2 bg-slate-100 border-none rounded-lg outline-none text-sm font-bold text-slate-700 focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all" 
                     placeholder="Buscar patología, síndrome, técnica..." 
                     value={query} 
                     onChange={e => setQuery(e.target.value)}
                     onKeyDown={e => e.key === 'Enter' && executeSearch(query)}
                   />
                   {query && <button onClick={() => setQuery('')} className="absolute right-3 top-2.5 text-slate-400 hover:text-slate-600"><X className="w-4 h-4"/></button>}
               </div>
               <button onClick={() => setViewMode('CREATE')} className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-xs font-bold shadow-sm flex items-center hover:bg-indigo-700 transition-colors shrink-0"><Plus className="w-4 h-4 mr-2"/> NUEVA</button>
           </div>

           {/* LOADING STATE */}
           {loading && (
               <div className="flex-1 flex flex-col items-center justify-center bg-white/80 backdrop-blur-sm z-30 absolute inset-0">
                   <Sparkles className="w-12 h-12 text-indigo-600 animate-spin mb-4"/>
                   <h3 className="text-lg font-black text-slate-800">GENERANDO FICHA TÉCNICA</h3>
                   <p className="text-sm text-slate-500">Consultando base de conocimiento clínica...</p>
               </div>
           )}

           {/* LIST VIEW (IF NO DATA SELECTED) */}
           {!data && viewMode === 'SEARCH' && (
               <div className="flex-1 overflow-y-auto p-6 animate-fade-in">
                   <div className={`p-6 rounded-2xl border mb-6 flex justify-between items-end bg-white border-slate-200 shadow-sm`}>
                        <div>
                            <h2 className={`text-2xl font-black uppercase tracking-tight text-slate-800 mb-1`}>{currentCategoryData?.category}</h2>
                            <p className="text-sm text-slate-500 font-medium">Seleccione una patología para ver su ficha técnica detallada.</p>
                        </div>
                        <div className={`p-3 rounded-xl bg-slate-50 text-slate-400`}>
                            {currentCategoryData && <currentCategoryData.icon className="w-8 h-8"/>}
                        </div>
                   </div>

                   <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                        {currentCategoryData?.items.filter(i => i.toLowerCase().includes(query.toLowerCase())).map((item, i) => (
                            <button key={i} onClick={() => executeSearch(item)} className="text-left p-4 rounded-xl bg-white border border-slate-200 hover:border-indigo-400 hover:shadow-md transition-all text-sm font-bold text-slate-700 flex justify-between items-center group active:scale-[0.99]">
                                <span className="truncate pr-2">{item}</span>
                                <ChevronRight className="w-4 h-4 text-slate-300 group-hover:text-indigo-500 transition-colors"/>
                            </button>
                        ))}
                   </div>

                   {currentCategoryData?.items.filter(i => i.toLowerCase().includes(query.toLowerCase())).length === 0 && (
                       <div className="text-center py-20 opacity-50">
                           <Search className="w-12 h-12 mx-auto mb-2 text-slate-300"/>
                           <p className="text-sm font-bold text-slate-400">No se encontraron resultados.</p>
                       </div>
                   )}
               </div>
           )}

           {/* CREATE MODE */}
           {viewMode === 'CREATE' && (
               <div className="flex-1 overflow-y-auto p-6 animate-fade-in-up bg-slate-50">
                   <div className="max-w-4xl mx-auto bg-white rounded-2xl shadow-lg border border-slate-200 overflow-hidden">
                       <div className="p-6 bg-indigo-600 text-white">
                           <h2 className="text-xl font-black uppercase mb-1 flex items-center"><PenTool className="w-5 h-5 mr-2"/> Creador de Fichas</h2>
                           <p className="text-indigo-200 text-xs">Genere contenido automáticamente con IA o rellene manualmente.</p>
                       </div>
                       <div className="p-6 space-y-6">
                           <div>
                               <label className="text-xs font-bold text-slate-500 uppercase mb-1 block">Nombre de la Patología</label>
                               <div className="flex gap-2">
                                   <input value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="flex-1 border-2 border-slate-200 rounded-xl p-3 text-lg font-bold text-slate-800 outline-none focus:border-indigo-500 transition-colors" placeholder="Ej: Insuficiencia Renal Aguda..." />
                                   <button onClick={handleAutoFill} disabled={isAutoFilling || !formData.name} className="bg-indigo-600 text-white px-6 rounded-xl font-black flex items-center hover:bg-indigo-700 transition-colors disabled:opacity-50 shadow-md">
                                       <Wand2 className={`w-5 h-5 mr-2 ${isAutoFilling ? 'animate-spin':''}`}/> AUTO-GENERAR
                                   </button>
                               </div>
                           </div>

                           <div className="grid md:grid-cols-2 gap-6">
                               <div className="space-y-4">
                                   <div>
                                       <label className="text-[10px] font-black text-slate-400 uppercase mb-1 block">DEFINICIÓN</label>
                                       <textarea value={formData.definition} onChange={e=>setFormData({...formData, definition: e.target.value})} className="w-full p-3 border rounded-lg h-24 text-sm resize-none bg-slate-50 focus:bg-white transition-colors outline-none focus:ring-2 ring-indigo-500/20 border-slate-200"/>
                                   </div>
                                   <div>
                                       <label className="text-[10px] font-black text-slate-400 uppercase mb-1 block">SISTEMA</label>
                                       <select value={formData.system} onChange={e=>setFormData({...formData, system: e.target.value})} className="w-full p-3 border rounded-lg text-sm bg-white outline-none border-slate-200 font-bold text-slate-700">
                                           {RAW_CATALOG.map(c=><option key={c.category} value={c.category}>{c.category}</option>)}
                                       </select>
                                   </div>
                               </div>
                               <div className="space-y-4">
                                   <div>
                                       <label className="text-[10px] font-black text-slate-400 uppercase mb-1 block">ETIOLOGÍA</label>
                                       <textarea value={formData.etiology} onChange={e=>setFormData({...formData, etiology: e.target.value})} className="w-full p-3 border rounded-lg h-24 text-sm resize-none bg-slate-50 focus:bg-white transition-colors outline-none focus:ring-2 ring-indigo-500/20 border-slate-200"/>
                                   </div>
                                   <div>
                                       <label className="text-[10px] font-black text-slate-400 uppercase mb-1 block">ALERTA CLÍNICA</label>
                                       <input value={formData.alert} onChange={e=>setFormData({...formData, alert: e.target.value})} className="w-full p-3 border border-rose-200 bg-rose-50 text-rose-900 rounded-lg text-sm font-bold outline-none" placeholder="Riesgo vital..."/>
                                   </div>
                               </div>
                           </div>

                           <div className="flex justify-end pt-4 border-t border-slate-100 gap-3">
                               <button onClick={() => setViewMode('SEARCH')} className="px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-slate-100 transition-colors text-xs">CANCELAR</button>
                               <button onClick={handleManualCreate} className="px-8 py-3 bg-emerald-600 text-white rounded-xl font-bold text-xs hover:bg-emerald-700 shadow-lg shadow-emerald-200 transition-all transform hover:-translate-y-0.5">GUARDAR FICHA</button>
                           </div>
                       </div>
                   </div>
               </div>
           )}

           {/* DETAIL MODE (FICHA TÉCNICA) */}
           {data && viewMode === 'SEARCH' && (
               <div className="flex-1 overflow-y-auto bg-slate-100 relative">
                   {/* HERO HEADER */}
                   <div className="bg-slate-900 text-white p-8 pb-12 relative overflow-hidden">
                       <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/20 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
                       <button onClick={() => setData(null)} className="absolute top-6 left-6 p-2 bg-white/10 hover:bg-white/20 rounded-full text-white transition-colors backdrop-blur-sm"><ArrowLeft className="w-5 h-5"/></button>

                       <div className="max-w-5xl mx-auto mt-4 relative z-10">
                           <div className="flex flex-wrap gap-2 mb-4">
                               <span className="bg-indigo-600 text-white text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider shadow-lg shadow-indigo-900/50">{data.system}</span>
                               <span className="bg-rose-600 text-white text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider shadow-lg shadow-rose-900/50">NANDA: {data.nandaDx.code}</span>
                           </div>
                           <h1 className="text-3xl md:text-5xl font-black uppercase tracking-tight text-white mb-6 leading-tight">{data.name}</h1>

                           <div className="flex gap-3 flex-wrap">
                               <button onClick={handleSave} disabled={isSaved} className={`px-5 py-2.5 rounded-lg text-xs font-bold flex items-center transition-all ${isSaved ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/50 cursor-default' : 'bg-emerald-600 hover:bg-emerald-500 text-white shadow-lg shadow-emerald-900/20'}`}>
                                   {isSaved ? <Check className="w-4 h-4 mr-2"/> : <Save className="w-4 h-4 mr-2"/>} {isSaved ? 'GUARDADO' : 'GUARDAR EN MI LISTA'}
                               </button>
                               <button onClick={() => setIsStudyMode(!isStudyMode)} className={`px-5 py-2.5 rounded-lg text-xs font-bold flex items-center transition-all ${isStudyMode ? 'bg-amber-400 text-black shadow-lg shadow-amber-900/20' : 'bg-white/10 text-white hover:bg-white/20 backdrop-blur-md border border-white/10'}`}>
                                   {isStudyMode ? <GraduationCap className="w-4 h-4 mr-2"/> : <EyeOff className="w-4 h-4 mr-2"/>} {isStudyMode ? 'MODO ESTUDIO ACTIVO' : 'MODO ESTUDIO'}
                               </button>
                           </div>
                       </div>
                   </div>

                   {/* CONTENT CARDS */}
                   <div className="max-w-5xl mx-auto px-6 -mt-8 pb-20 space-y-8 relative z-10">

                       {/* DEFINITION CARD */}
                       <div className="bg-white rounded-2xl shadow-xl border border-slate-200 p-8">
                           <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center"><Info className="w-4 h-4 mr-2"/> DEFINICIÓN Y CONCEPTO</h3>
                           <p className="text-lg text-slate-800 font-medium leading-relaxed border-l-4 border-indigo-500 pl-6">{data.definition}</p>

                           <div className="grid md:grid-cols-3 gap-6 mt-8 pt-8 border-t border-slate-100">
                               <div>
                                   <h4 className="text-[10px] font-black text-slate-400 uppercase mb-2">ETIOLOGÍA</h4>
                                   <p className={`text-sm font-bold text-slate-700 ${blurClass}`}>{data.etiology}</p>
                               </div>
                               <div>
                                   <h4 className="text-[10px] font-black text-slate-400 uppercase mb-2">VALORACIÓN</h4>
                                   <p className={`text-sm font-bold text-slate-700 ${blurClass}`}>{data.initialAssessment}</p>
                               </div>
                               <div>
                                   <h4 className="text-[10px] font-black text-slate-400 uppercase mb-2">NOTA CLÍNICA</h4>
                                   <p className={`text-sm font-bold text-slate-700 ${blurClass}`}>{data.clinicalNote}</p>
                               </div>
                           </div>
                       </div>

                       <div className="grid md:grid-cols-2 gap-6">
                           {/* CLINICAL PICTURE */}
                           <div className="bg-white rounded-2xl shadow-md border border-slate-200 p-6 h-full">
                               <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-6 flex items-center border-b border-slate-100 pb-4"><Activity className="w-4 h-4 mr-2 text-rose-500"/> CUADRO CLÍNICO</h3>
                               <div className="space-y-6">
                                   <div>
                                       <span className="text-[10px] font-black bg-indigo-50 text-indigo-700 px-2 py-1 rounded uppercase mb-2 inline-block">SÍNTOMAS (SUBJETIVO)</span>
                                       <ul className={`space-y-2 mt-2 ${blurClass}`}>
                                           {data.symptoms.map((s,i) => <li key={i} className="text-sm font-medium text-slate-700 flex items-start"><span className="w-1.5 h-1.5 bg-indigo-400 rounded-full mt-1.5 mr-2.5 shrink-0"/>{s}</li>)}
                                       </ul>
                                   </div>
                                   <div>
                                       <span className="text-[10px] font-black bg-rose-50 text-rose-700 px-2 py-1 rounded uppercase mb-2 inline-block">SIGNOS (OBJETIVO)</span>
                                       <ul className={`space-y-2 mt-2 ${blurClass}`}>
                                            {data.signs.map((s,i) => <li key={i} className="text-sm font-medium text-slate-700 flex items-start"><span className="w-1.5 h-1.5 bg-rose-400 rounded-full mt-1.5 mr-2.5 shrink-0"/>{s}</li>)}
                                       </ul>
                                   </div>
                               </div>
                           </div>

                           {/* PAE & TREATMENT */}
                           <div className="flex flex-col gap-6">

                               {/* PAE CARD */}
                               <div className="bg-slate-800 text-slate-300 rounded-2xl shadow-lg border border-slate-700 p-6 flex-1">
                                   <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center border-b border-slate-700 pb-4"><ClipboardList className="w-4 h-4 mr-2 text-emerald-400"/> PROCESO ENFERMERO</h3>

                                   <div className={`space-y-6 ${blurClass}`}>
                                       <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-700">
                                           <div className="text-[10px] font-black text-rose-400 uppercase mb-1">DIAGNÓSTICO NANDA</div>
                                           <div className="font-bold text-white text-sm">{data.nandaDx.label}</div>
                                           <div className="text-xs text-slate-400 mt-1 italic">r/c {data.nandaDx.rc}</div>
                                       </div>

                                       <div className="grid grid-cols-2 gap-4">
                                           <div>
                                               <div className="text-[10px] font-black text-blue-400 uppercase mb-2">NOC (RESULTADOS)</div>
                                               <p className="text-xs font-medium text-slate-300 leading-relaxed">{data.noc}</p>
                                           </div>
                                           <div>
                                               <div className="text-[10px] font-black text-emerald-400 uppercase mb-2">NIC (INTERVENCIONES)</div>
                                               <ul className="text-xs font-medium text-slate-300 space-y-1">
                                                   <li>• {data.nic.monitoring}</li>
                                                   <li>• {data.nic.management}</li>
                                               </ul>
                                           </div>
                                       </div>
                                   </div>
                               </div>

                               {/* PHARM CARD */}
                               <div className="bg-white rounded-2xl shadow-md border border-slate-200 p-6">
                                   <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4 flex items-center"><Pill className="w-4 h-4 mr-2 text-purple-500"/> TRATAMIENTO</h3>
                                   <div className={`flex flex-wrap gap-2 ${blurClass}`}>
                                       {data.treatments.map((t,i) => (
                                           <button key={i} onClick={() => onNavigate(ViewState.PHARMACOLOGY, {query: t})} className="bg-purple-50 text-purple-700 border border-purple-100 px-3 py-1.5 rounded-lg text-xs font-bold hover:bg-purple-600 hover:text-white transition-all shadow-sm flex items-center group">
                                               {t} <ArrowRight className="w-3 h-3 ml-1 opacity-50 group-hover:opacity-100"/>
                                           </button>
                                       ))}
                                   </div>
                               </div>
                           </div>
                       </div>
                   </div>

               </div>
           )}

       </div>
    </div>
  );
};
]]></content>
</change>
